    sensorB->valueChanged();
    const int afterSecondBinding = aggregator->notificationCount();

    rollback();

    sensorA->valueChanged();
    const int afterRollback = aggregator->notificationCount();

    return RollbackObservation{
        afterSecondBinding,
        afterRollback,
