#pragma once

#include <reaction/reaction.h>
#include <memory>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        m_notifications++;
    }

    int notificationCount() const {
        return m_notifications;
    }

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // Step 1: Create RecordingNode instances
    auto sensor1 = std::make_shared<RecordingNode>();
    auto sensor2 = std::make_shared<RecordingNode>();

    // Step 2: Get observer graph instance
    auto observerGraph = reaction::ObserverGraph::getInstance();

    // Step 3: Register nodes
    observerGraph->addNode(sensor1);
    observerGraph->addNode(sensor2);

    // Step 4: Set up initial dependency
    observerGraph->addObserver(sensor1, sensor2);

    // Step 5: Save node state for rollback
    auto originalState = observerGraph->getObservers(sensor2);

    // Step 6: Replace dependencies transactionally
    // Remove existing observers and set up new ones
    observerGraph->resetNode(sensor2);
    // Add new dependency (example: sensor2 now observes sensor1)
    observerGraph->addObserver(sensor2, sensor1);

    // Step 7: Trigger notification on second sensor
    sensor2->valueChanged(true);

    // Step 8: Record notification count after second binding
    int afterSecondBinding = sensor1->notificationCount();

    // Step 9: Execute rollback
    observerGraph->resetNode(sensor2); // Clear current observers
    // Restore original dependencies
    for (auto& observer : originalState) {
        observerGraph->addObserver(sensor2, observer);
    }

    // Step 10: Trigger notification on first sensor
    sensor1->valueChanged(true);

    // Step 11: Record notification count after rollback
    int afterRollback = sensor2->notificationCount();

    // Step 12: Return notification counts
    return {afterSecondBinding, afterRollback};
}

}  // namespace test_reaction
